<?php namespace App\Services\Finance; use App\Models\{BillingDocument,Order,PaymentRecord,User}; use Illuminate\Validation\ValidationException;
class BillingDocumentService{public function __construct(private PaymentNumberGenerator $numbers){}public function createDraftInvoiceForOrder(Order $order,User $actor):BillingDocument{$q=$order->latestPriceQuote();if(!$q)throw ValidationException::withMessages(['quote'=>'A real quote is required.']);$d=BillingDocument::create(['document_number'=>$this->numbers->document('invoice'),'document_type'=>'invoice','status'=>'draft','order_id'=>$order->id,'customer_id'=>$order->customer_id,'order_price_quote_id'=>$q->id,'currency'=>$q->currency,'subtotal_amount'=>$q->subtotal,'tax_amount'=>$q->tax_total,'total_amount'=>$q->total,'created_by_id'=>$actor->id,'updated_by_id'=>$actor->id]);$this->event($d,$actor,'created',null,'draft','Draft invoice created from real quote.');return $d;}public function issueInvoice(BillingDocument $d,User $a):BillingDocument{if(!$d->customer_id||(float)$d->total_amount<=0)throw ValidationException::withMessages(['invoice'=>'Customer owner and positive total are required.']);$d->update(['status'=>'issued','issued_at'=>now(),'updated_by_id'=>$a->id]);$this->event($d,$a,'issued','draft','issued');return $d;}public function voidInvoice(BillingDocument $d,User $a,string $reason):BillingDocument{if(blank($reason))throw ValidationException::withMessages(['reason'=>'Reason required.']);$from=$d->status;$d->update(['status'=>'void','voided_at'=>now(),'updated_by_id'=>$a->id]);$this->event($d,$a,'voided',$from,'void',$reason);return $d;}public function createReceiptForPayment(PaymentRecord $p,User $a):BillingDocument{if($p->status!=='captured')throw ValidationException::withMessages(['payment'=>'Receipt requires a real captured payment.']);throw ValidationException::withMessages(['payment'=>'Receipt generation is unavailable until a real provider is connected.']);}public function addBillingNote(BillingDocument $d,User $a,string $note):void{$this->event($d,$a,'note_added',null,null,$note);}private function event(BillingDocument $d,User $a,string $type,?string $from,?string $to,?string $description=null):void{$d->events()->create(['actor_id'=>$a->id,'event_type'=>$type,'from_value'=>$from,'to_value'=>$to,'description'=>$description,'created_at'=>now()]);}}
